// Fetch primary page image from Wikipedia in a specific language (highly accurate)
async function fetchWikipediaPageImage(query: string, lang: 'en' | 'pt', allowSvg: boolean = false): Promise<string | null> {
  const cleanQuery = query.toLowerCase().trim();
  try {
    const url = `https://${lang}.wikipedia.org/w/api.php?action=query&format=json&prop=pageimages&generator=search&piprop=original&gsrsearch=${encodeURIComponent(cleanQuery)}&gsrlimit=5&origin=*`;
    const res = await fetch(url, {
      headers: {
        'User-Agent': 'OQueEQuizApp/1.0 (shla2701@gmail.com) Node/Fetch'
      }
    });
    if (res.ok) {
      const data = await res.json() as any;
      const pagesObj = data.query?.pages;
      if (pagesObj) {
        // Sort results by search rank index (ascending, index 1 is the most relevant)
        const sortedPages = Object.values(pagesObj).sort((a: any, b: any) => (a.index || 0) - (b.index || 0));
        for (const page of sortedPages as any[]) {
          const originalUrl = page?.original?.source;
          if (originalUrl && (originalUrl.startsWith('http://') || originalUrl.startsWith('https://'))) {
            // Keep SVG files if allowed (especially important for clean flags and logos)
            if (allowSvg || !originalUrl.toLowerCase().endsWith('.svg')) {
              return originalUrl;
            }
          }
        }
      }
    }
  } catch (err) {
    console.error(`Wikipedia [${lang}] fetch failed for "${cleanQuery}":`, err);
  }
  return null;
}

