export function getFallbackQuestions(category: string, difficulty: string, categoryName: string): any[] {
  // 1. Filter questions by category
  let filtered = FALLBACK_QUESTIONS.filter(q => category === 'all' || q.category === category);

  // If we didn't find any for that category, let's grab all of them
  if (filtered.length === 0) {
    filtered = [...FALLBACK_QUESTIONS];
  }

  // 2. Filter or sort by difficulty if possible, otherwise keep whatever is available to fill 20 slots
  let difficultyFiltered = filtered.filter(q => q.difficulty === difficulty);
  
  // Combine difficulty-specific with other difficulties of same category to make sure we have plenty of questions
  const others = filtered.filter(q => q.difficulty !== difficulty);
  const pool = [...difficultyFiltered, ...others];

  // 3. Shuffle the pool to give variety
  const shuffled = [...pool].sort(() => Math.random() - 0.5);

  // 4. Extract 20 questions. If we have less than 20 (e.g. specific categories), we supplement with other categories
  let selected = shuffled.slice(0, 20);

  if (selected.length < 20) {
    const remainingCount = 20 - selected.length;
    const usedItems = new Set(selected.map(q => q.item));
    const supplementPool = FALLBACK_QUESTIONS.filter(q => !usedItems.has(q.item))
      .sort(() => Math.random() - 0.5);
    selected = [...selected, ...supplementPool.slice(0, remainingCount)];
  }

  // Make sure we have exactly 20
  selected = selected.slice(0, 20);

  // 5. Transform into the final client format
  return selected.map((q, index) => {
    // Generate standard image placeholder gradient or specific beautiful unsplash fallback link
    // The server will try to fetch dynamic Unsplash anyway, but this is a double backup
    const defaultImg = q.category === 'astronomia' 
      ? 'https://images.unsplash.com/photo-1506318137071-a8e063b4bec0?w=600'
      : q.category === 'animais'
      ? 'https://images.unsplash.com/photo-1472491861675-415080c7f6f4?w=600'
      : q.category === 'tecnologia'
      ? 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=600'
      : q.category === 'construcoes'
      ? 'https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=600'
      : 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=600';

    return {
      id: `q-fallback-${Date.now()}-${index}-${Math.floor(Math.random() * 1000)}`,
      type: 'multiple',
      item: q.item,
      description: q.description,
      imageUrl: defaultImg, // Will be overridden or used as ultimate fallback
      category: categoryName,
      alternatives: q.alternatives || [q.item, 'Opção B', 'Opção C', 'Opção D', 'Opção E', 'Opção F'],
    };
  });
}
